/** PEM → DER (Uint8Array). chain.ts içinde roots[] olarak kullanılır. */
export function kamuSmRootsDer(): Uint8Array[] {
  return KAMUSM_ROOTS_PEM.map((pem) => pemToDer(pem));
}

function pemToDer(pem: string): Uint8Array {
  const b64 = pem.replace(/-----BEGIN [^-]+-----|-----END [^-]+-----|\s+/g, "");
  return new Uint8Array(Buffer.from(b64, "base64"));
}
